module RefModule(clk, en, d, q);  

    input  clk;  
    input en;  
    input [7:0] d;  
    output  [7:0] q;  
    reg   [7:0]  q; 

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
          begin
            if (en)
                q <= d;
          end  

endmodule
